const fs = require("fs");
const inp = $input.first().json;
const body = inp.body !== undefined ? inp.body : inp;
const filePath = "/data/portal/services.json";
const data = JSON.parse(fs.readFileSync(filePath, "utf8"));

const id = (body.id || (body.name || "").toLowerCase().replace(/[^a-z0-9]+/g, "-")).replace(/^-+|-+$/g, "");
const newService = {
  id,
  name: body.name || id,
  url: body.url || "",
  description: body.description || "",
  icon: body.icon || "box",
  category: body.category || "infra",
  favorite: false,
  ssoTier: body.ssoTier || 3
};
if (body.sshTarget) newService.sshTarget = body.sshTarget;
if (body.apiProvider) newService.apiProvider = body.apiProvider;

const idx = data.services.findIndex(s => s.id === id);
if (idx > -1) {
  data.services[idx] = { ...data.services[idx], ...newService };
} else {
  data.services.push(newService);
}

fs.writeFileSync(filePath, JSON.stringify(data, null, 2));
return [{ json: { status: "ok", action: "provisioned", service: newService, provisioned_at: new Date().toISOString() } }];

